 27→import org.xmlpull.v1.XmlPullParser
 28→import java.util.concurrent.atomic.AtomicReference
 29→
 30→object PreferenceTestUtils {
 31→    private fun getAttrFromXml(context: Context, @XmlRes xml: Int, attrName: String, namespace: String = AnkiDroidApp.ANDROID_NAMESPACE): List<String> {
 32→        val occurrences = mutableListOf<String>()
 33→
 34→        val xrp = context.resources.getXml(xml).apply {
 35→            setFeature(XmlPullParser.FEATURE_PROCESS_NAMESPACES, true)
 36→            setFeature(XmlPullParser.FEATURE_REPORT_NAMESPACE_ATTRIBUTES, true)
 37→        }
 38→
 39→        while (xrp.eventType != XmlPullParser.END_DOCUMENT) {
 40→            if (xrp.eventType == XmlPullParser.START_TAG) {
 41→                val attr = xrp.getAttributeValue(namespace, attrName)
 42→                if (attr != null) {
 43→                    occurrences.add(attr)
 44→                }
 45→            }
 46→            xrp.next()
 47→        }
 48→        return occurrences.toList()
 49→    }
 50→
 51→    /** @return fragments found on [xml] */
 52→    private fun getFragmentsFromXml(context: Context, @XmlRes xml: Int): List<Fragment> {
 53→        return getAttrFromXml(context, xml, "fragment").map { getInstanceFromClassName(it) }
 54→    }
 55→
 56→    /** @return recursively fragments found on [xml] and on their children **/
 57→    private fun getFragmentsFromXmlRecursively(context: Context, @XmlRes xml: Int): List<Fragment> {
 58→        val fragments = getFragmentsFromXml(context, xml).toMutableList()
 59→        for (fragment in fragments.filterIsInstance<SettingsFragment>()) {
 60→            fragments.addAll(getFragmentsFromXmlRecursively(context, fragment.preferenceResource))
 61→        }
 62→        return fragments.toList()
 63→    }
 64→
 65→    /** @return [List] of all the distinct preferences fragments **/
 66→    fun getAllPreferencesFragments(context: Context): List<Fragment> {
 67→        val fragments = getFragmentsFromXmlRecursively(context, R.xml.preference_headers) + HeaderFragment()
 68→        return fragments.distinctBy { it::class } // and remove any repeated fragments
 69→    }
 70→
 71→    private fun attrValueToString(value: String, context: Context): String {
 72→        return if (value.startsWith("@")) {
 73→            context.getString(value.substring(1).toInt())
 74→        } else {
 75→            value
 76→        }
 77→    }
 78→
 79→    fun getKeysFromXml(context: Context, @XmlRes xml: Int): List<String> {
 80→        return getAttrFromXml(context, xml, "key").map { attrValueToString(it, context) }
 81→    }
 82→
 83→    private fun getControlPreferencesKeys(): List<String> {
 84→        // control preferences are built dynamically instead of statically in a XML
 85→        return ViewerCommand.values().map { it.preferenceKey }
 86→    }
 87→
 88→    fun getAllPreferenceKeys(context: Context): Set<String> {
 89→        return getAllPreferencesFragments(context)
 90→            .filterIsInstance<SettingsFragment>()
 91→            .map { it.preferenceResource }
 92→            .flatMap { getKeysFromXml(context, it) }
 93→            .union(getControlPreferencesKeys())
 94→    }
 95→
 96→    fun getAllCustomButtonKeys(context: Context): Set<String> {
 97→        val ret = AtomicReference<Set<String>>()
 98→        val i = CustomButtonsSettingsFragment.getSubscreenIntent(context)
 99→        ActivityScenario.launch<Preferences>(i).use { scenario ->
100→            scenario.moveToState(Lifecycle.State.STARTED)
101→            scenario.onActivity { a: Preferences ->
102→                val customButtonsFragment = a.supportFragmentManager
103→                    .findFragmentByTag(CustomButtonsSettingsFragment::class.java.name) as CustomButtonsSettingsFragment
104→                ret.set(customButtonsFragment.allKeys())
105→            }
106→        }
107→        val preferenceKeys = ret.get()?.toMutableSet() ?: throw IllegalStateException("no keys were set")
108→        preferenceKeys.remove("reset_custom_buttons")
109→        return preferenceKeys
110→    }
111→}
