package com.ichi2.anki.preferences

import androidx.preference.PreferenceCategory
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.CommandGroup
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        // Add commands to their respective category groups
        for (group in CommandGroup.values()) {
            val category = requirePreference<PreferenceCategory>(group.preferenceKey)
            addControlPreferencesForGroup(category, group)
        }
    }

    /**
     * Attaches [ControlPreference] elements for a specific [CommandGroup] to its [PreferenceCategory]
     */
    private fun addControlPreferencesForGroup(category: PreferenceCategory, group: CommandGroup) {
        for (command in ViewerCommand.values().filter { it.group == group }) {
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }

    /**
     * Attaches all possible [ControlPreference] elements to a given [PreferenceCategory]
     * @deprecated Use [addControlPreferencesForGroup] for organized command categories
     */
    @Deprecated("Use addControlPreferencesForGroup instead for better organization by category")
    fun addAllControlPreferencesToCategory(category: PreferenceCategory) {
        for (command in ViewerCommand.values()) {
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }
}"}

