package com.ichi2.anki.cardviewer

import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.hamcrest.Matchers.greaterThan
import org.hamcrest.Matchers.notNullValue
import org.junit.Test

/**
 * Tests to verify that all [ViewerCommand]s are properly organized into [CommandGroup] categories
 */
class CommandGroupTest {

    @Test
    fun `all commands should be assigned to a category group`() {
        // Every ViewerCommand must have a non-null group
        for (command in ViewerCommand.values()) {
            assertThat(
                "Command $command should have a group assigned",
                command.group,
                notNullValue()
            )
        }
    }

    @Test
    fun `all command groups should contain at least one command`() {
        // Every CommandGroup should have at least one ViewerCommand assigned to it
        for (group in CommandGroup.values()) {
            val commandsInGroup = ViewerCommand.values().filter { it.group == group }
            assertThat(
                "Group $group should have at least one command",
                commandsInGroup.size,
                greaterThan(0)
            )
        }
    }

    @Test
    fun `answer buttons group should contain answer-related commands`() {
        val answerCommands = ViewerCommand.values().filter { it.group == CommandGroup.ANSWER_BUTTONS }
        assertThat(answerCommands.contains(ViewerCommand.SHOW_ANSWER), equalTo(true))
        assertThat(answerCommands.contains(ViewerCommand.FLIP_OR_ANSWER_EASE1), equalTo(true))
        assertThat(answerCommands.contains(ViewerCommand.FLIP_OR_ANSWER_EASE2), equalTo(true))
        assertThat(answerCommands.contains(ViewerCommand.FLIP_OR_ANSWER_EASE3), equalTo(true))
        assertThat(answerCommands.contains(ViewerCommand.FLIP_OR_ANSWER_EASE4), equalTo(true))
    }

    @Test
    fun `flags group should contain flag-related commands`() {
        val flagCommands = ViewerCommand.values().filter { it.group == CommandGroup.FLAGS }
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_RED), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_ORANGE), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_GREEN), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_BLUE), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_PINK), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_TURQUOISE), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.TOGGLE_FLAG_PURPLE), equalTo(true))
        assertThat(flagCommands.contains(ViewerCommand.UNSET_FLAG), equalTo(true))
    }

    @Test
    fun `whiteboard group should contain whiteboard-related commands`() {
        val whiteboardCommands = ViewerCommand.values().filter { it.group == CommandGroup.WHITEBOARD }
        assertThat(whiteboardCommands.contains(ViewerCommand.TOGGLE_WHITEBOARD), equalTo(true))
        assertThat(whiteboardCommands.contains(ViewerCommand.CLEAR_WHITEBOARD), equalTo(true))
        assertThat(whiteboardCommands.contains(ViewerCommand.CHANGE_WHITEBOARD_PEN_COLOR), equalTo(true))
    }

    @Test
    fun `card note group should contain card and note related commands`() {
        val cardNoteCommands = ViewerCommand.values().filter { it.group == CommandGroup.CARD_NOTE }
        assertThat(cardNoteCommands.contains(ViewerCommand.EDIT), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.MARK), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.BURY_CARD), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.BURY_NOTE), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.SUSPEND_CARD), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.SUSPEND_NOTE), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.DELETE), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.TAG), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.CARD_INFO), equalTo(true))
        assertThat(cardNoteCommands.contains(ViewerCommand.RESCHEDULE_NOTE), equalTo(true))
    }

    @Test
    fun `navigation group should contain navigation-related commands`() {
        val navCommands = ViewerCommand.values().filter { it.group == CommandGroup.NAVIGATION }
        assertThat(navCommands.contains(ViewerCommand.EXIT), equalTo(true))
        assertThat(navCommands.contains(ViewerCommand.PAGE_UP), equalTo(true))
        assertThat(navCommands.contains(ViewerCommand.PAGE_DOWN), equalTo(true))
        assertThat(navCommands.contains(ViewerCommand.ABORT_AND_SYNC), equalTo(true))
    }

    @Test
    fun `audio group should contain audio-related commands`() {
        val audioCommands = ViewerCommand.values().filter { it.group == CommandGroup.AUDIO }
        assertThat(audioCommands.contains(ViewerCommand.PLAY_MEDIA), equalTo(true))
        assertThat(audioCommands.contains(ViewerCommand.RECORD_VOICE), equalTo(true))
        assertThat(audioCommands.contains(ViewerCommand.REPLAY_VOICE), equalTo(true))
    }

    @Test
    fun `total command count should remain consistent`() {
        // This test ensures we don't accidentally lose or duplicate commands when reorganizing
        val totalCommands = ViewerCommand.values().size
        val commandsInAllGroups = CommandGroup.values().sumOf { group ->
            ViewerCommand.values().count { it.group == group }
        }
        assertThat(
            "Total commands should equal sum of commands in all groups",
            commandsInAllGroups,
            equalTo(totalCommands)
        )
    }
}
"}

